237	```ts
238	/* ────────────────────────────────────────────────────────────────────── */
239	/* C16 Column — single-click placement                                      */
240	/* ────────────────────────────────────────────────────────────────────── */
241	
242	export type ColumnState = { phase: 'idle' };
243	
244	export type ColumnEvent =
245	  | { kind: 'activate' }
246	  | { kind: 'deactivate' }
247	  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
248	  | { kind: 'cancel' };
249	
250	export interface ColumnEffect {
251	  commitColumn?: { positionMm: { xMm: number; yMm: number } };
252	  stillActive: boolean;
253	}
254	
255	export function initialColumnState(): ColumnState {
256	  return { phase: 'idle' };
257	}
258	
259	export function reduceColumn(
260	  state: ColumnState,
261	  event: ColumnEvent,
262	): { state: ColumnState; effect: ColumnEffect } {
263	  if (event.kind === 'deactivate') {
264	    return { state: initialColumnState(), effect: { stillActive: false } };
265	  }
266	  if (event.kind === 'activate' || event.kind === 'cancel') {
267	    return { state: initialColumnState(), effect: { stillActive: event.kind === 'activate' } };
268	  }
269	  if (event.kind === 'click') {
270	    return {
271	      state: initialColumnState(),
272	      effect: { commitColumn: { positionMm: event.pointMm }, stillActive: true },
273	    };
274	  }
275	  return { state, effect: { stillActive: true } };
276	}
277	
278	/* ────────────────────────────────────────────────────────────────────── */
279	/* C17 Beam — two-click line placement                                      */
280	/* ────────────────────────────────────────────────────────────────────── */
281	
282	export type BeamState =
283	  | { phase: 'idle' }
284	  | { phase: 'first-point'; startMm: { xMm: number; yMm: number } };
285	
286	export type BeamEvent =
287	  | { kind: 'activate' }
288	  | { kind: 'deactivate' }
289	  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
290	  | { kind: 'cancel' };
291	
292	export interface BeamEffect {
293	  commitBeam?: { startMm: { xMm: number; yMm: number }; endMm: { xMm: number; yMm: number } };
294	  stillActive: boolean;
295	}
296	
297	export function initialBeamState(): BeamState {
298	  return { phase: 'idle' };
299	}
300	
301	export function reduceBeam(
302	  state: BeamState,
303	  event: BeamEvent,
304	): { state: BeamState; effect: BeamEffect } {
305	  if (event.kind === 'deactivate') {
306	    return { state: initialBeamState(), effect: { stillActive: false } };
307	  }
308	  if (event.kind === 'activate' || event.kind === 'cancel') {
309	    return { state: initialBeamState(), effect: { stillActive: event.kind === 'activate' } };
310	  }
311	  if (event.kind === 'click') {
312	    if (state.phase === 'idle') {
313	      return {
314	        state: { phase: 'first-point', startMm: event.pointMm },
315	        effect: { stillActive: true },
316	      };
317	    }
318	    if (state.phase === 'first-point') {
319	      return {
320	        state: initialBeamState(),
321	        effect: {
322	          commitBeam: { startMm: state.startMm, endMm: event.pointMm },
323	          stillActive: true,
324	        },
325	      };
326	    }
327	  }
328	  return { state, effect: { stillActive: true } };
329	}
330	```
