1	/** Schedule payload totals + sort-direction helpers (shared by SchedulePanel and scheduleTableRenderer_v1). */
2	
3	/** Precedence matches server `_resolve_sort_descending` (filters, then grouping). */
4	export function resolveScheduleSortDescending(
5	  filters: Record<string, unknown>,
6	  grouping: Record<string, unknown> | undefined,
7	): boolean {
8	  for (const src of [filters, grouping ?? {}]) {
9	    const v = src.sortDescending ?? src.sort_descending;
10	    if (typeof v === 'boolean') return v;
11	    if (typeof v === 'string' && ['true', '1', 'yes'].includes(v.trim().toLowerCase())) return true;
12	  }
13	  return false;
14	}
15	
16	export function scheduleTotalsReadoutParts(totals: Record<string, unknown> | undefined): string[] {
17	  if (!totals) return [];
18	
19	  const kind = String(totals.kind ?? '');
20	
21	  const parts: string[] = [];
22	
23	  parts.push(`${totals.rowCount ?? totals.row_count ?? '?'} rows`);
24	
25	  if (kind === 'room') {
26	    parts.push(`sum area ${Number(totals.areaM2 ?? 0).toFixed(3)} m2`);
27	    parts.push(`sum perimeter ${Number(totals.perimeterM ?? 0).toFixed(3)} m`);
