44	    scheduleId: string,
45	    filters: Record<string, unknown>,
46	    grouping?: Record<string, unknown>,
47	  ) => void;
48	}) {
49	  const [openingWidthGtDraft, setOpeningWidthGtDraft] = useState('');
50	  const [openingWidthLtDraft, setOpeningWidthLtDraft] = useState('');
51	  const [roomAreaGtDraft, setRoomAreaGtDraft] = useState('');
52	  const [roomAreaLtDraft, setRoomAreaLtDraft] = useState('');
53	
54	  const openingToolbarScheduleEl =
55	    tab === 'doors' || tab === 'windows' ? elementsById[scheduleId] : undefined;
56	  const roomToolbarScheduleEl = tab === 'rooms' ? elementsById[scheduleId] : undefined;
57	
58	  useEffect(() => {
59	    queueMicrotask(() => {
60	      if (openingToolbarScheduleEl?.kind !== 'schedule') {
61	        setOpeningWidthGtDraft('');
62	        setOpeningWidthLtDraft('');
63	        return;
64	      }
65	      const f0 = { ...(openingToolbarScheduleEl.filters ?? {}) } as Record<string, unknown>;
66	      const t = parseWidthMmGtThreshold(f0);
67	      setOpeningWidthGtDraft(t !== null ? String(t) : '');
68	      const u = parseWidthMmLtThreshold(f0);
69	      setOpeningWidthLtDraft(u !== null ? String(u) : '');
70	    });
71	  }, [openingToolbarScheduleEl]);
72	
73	  useEffect(() => {
74	    queueMicrotask(() => {
75	      if (roomToolbarScheduleEl?.kind !== 'schedule') {
76	        setRoomAreaGtDraft('');
77	        setRoomAreaLtDraft('');
78	        return;
79	      }
80	      const f0 = { ...(roomToolbarScheduleEl.filters ?? {}) } as Record<string, unknown>;
81	      const minArea = parseNumericFilterRuleThreshold(f0, 'areaM2', 'gt');
82	      setRoomAreaGtDraft(minArea !== null ? String(minArea) : '');
83	      const maxArea = parseNumericFilterRuleThreshold(f0, 'areaM2', 'lt');
84	      setRoomAreaLtDraft(maxArea !== null ? String(maxArea) : '');
85	    });
86	  }, [roomToolbarScheduleEl]);
87	
88	  // Guard: only render when all conditions are met (caller pre-validates, but double-check el)
89	  const el = elementsById[scheduleId];
90	  if (!el || el.kind !== 'schedule') return null;
91	  if (!srvActive || srvActive.scheduleId !== scheduleId || !modelId) return null;
92	
93	  const f = { ...(el.filters ?? {}) } as Record<string, unknown>;
94	
95	  const ghRaw = f.groupingHint ?? f.grouping_hint;
96	  const gkEl = el.grouping as { groupKeys?: unknown } | undefined;
97	  const gkRaw = gkEl?.groupKeys;
98	  const hintsFromFilters = Array.isArray(ghRaw)
99	    ? ghRaw.filter((x): x is string => typeof x === 'string')
100	    : [];
101	  const hintsFromGrouping = Array.isArray(gkRaw)
102	    ? gkRaw.filter((x): x is string => typeof x === 'string')
103	    : [];
104	  const hintList = hintsFromFilters.length > 0 ? hintsFromFilters : hintsFromGrouping;
105	  const hintSet = new Set(hintList);
106	
107	  const sortKeys = scheduleSortKeyChoices(tab);
108	  const groupOpts = scheduleGroupingKeyChoices(tab);
109	
110	  const sortVal = String(
111	    f.sortBy ?? (el.grouping as { sortBy?: string } | undefined)?.sortBy ?? sortKeys[0] ?? 'name',
112	  );
113	
114	  const sortDesc = resolveScheduleSortDescending(f, el.grouping as Record<string, unknown>);
115	
116	  const orderedHints = (): string[] => groupOpts.filter((gk) => hintSet.has(gk));
117	
118	  const groupingPayload = (hints: string[]) => ({
