144	  const numericRuleBase = (): Record<string, unknown> => ({
145	    ...f,
146	    sortBy: sortVal,
147	    groupingHint: orderedHints(),
148	    filterEquals: feObj,
149	    sortDescending: sortDesc,
150	  });
