154	      data-testid="schedule-definition-toolbar"
155	      className="mt-2 rounded border border-border/60 bg-background/40 p-2 text-[10px] text-muted"
156	    >
157	      <div className="font-semibold text-foreground">
158	        Schedule definition · upsertScheduleFilters
159	      </div>
160	
161	      <div className="mt-2 flex flex-wrap items-center gap-3">
162	        <label className="flex flex-wrap items-center gap-2">
163	          <span>Sort field</span>
164	
165	          <select
166	            className="rounded border border-border bg-background px-2 py-0.5 font-mono"
167	            value={sortVal}
168	            onChange={(e) => {
169	              const sb = e.target.value;
170	              const hints = orderedHints();
171	              commit(
172	                { ...f, sortBy: sb, groupingHint: hints, sortDescending: sortDesc },
173	                {
174	                  ...(el.grouping as Record<string, unknown>),
175	                  sortBy: sb,
176	                  groupKeys: hints,
177	                  sortDescending: sortDesc,
178	                },
179	              );
180	            }}
181	          >
182	            {sortKeys.map((k) => (
183	              <option key={k} value={k}>
184	                {k}
185	              </option>
186	            ))}
187	          </select>
188	        </label>
189	
190	        <label className="flex cursor-pointer items-center gap-2">
191	          <input
192	            type="checkbox"
193	            data-testid="schedule-sort-descending"
194	            checked={sortDesc}
195	            onChange={(e) => {
196	              const desc = e.target.checked;
197	              const hints = orderedHints();
198	              commit(
199	                {
200	                  ...f,
201	                  sortBy: sortVal,
202	                  groupingHint: hints,
203	                  sortDescending: desc,
204	                },
205	                {
206	                  ...(el.grouping as Record<string, unknown>),
207	                  sortBy: sortVal,
208	                  groupKeys: hints,
209	                  sortDescending: desc,
210	                },
211	              );
212	            }}
213	          />
214	          <span>Descending</span>
215	        </label>
216	
217	        {lf && activeLevelId ? (
218	          <label className="flex cursor-pointer items-center gap-2">
219	            <input
220	              type="checkbox"
221	              checked={levelRestricted}
222	              onChange={(e) => {
223	                const on = e.target.checked;
224	                const hints = orderedHints();
225	                const nextFe = { ...feObj };
226	                if (on) nextFe[lf] = activeLevelId;
227	                else delete nextFe[lf];
228	                commit(
229	                  {
230	                    ...f,
231	                    sortBy: sortVal,
232	                    groupingHint: hints,
